SELECT s.id AS shot_id, s.scene_id, s.sort_order, s.prompt, s.prompt_en, s.generated_image_url, s.generated_video_url, s.status AS shot_status, s.review_comment, s.version AS shot_version, s.generation_attempts FROM shot s WHERE s.scene_id = #{sceneId}
AND s.status = #{status}
ORDER BY s.sort_order ASC

SELECT s.id AS shot_id, s.scene_id, s.sort_order, s.prompt, s.prompt_en, s.generated_image_url, s.generated_video_url, s.status AS shot_status, s.review_comment, s.version AS shot_version, s.generation_attempts FROM shot s INNER JOIN scene sc ON s.scene_id = sc.id AND sc.deleted = 0 INNER JOIN episode e ON sc.episode_id = e.id AND e.deleted = 0 WHERE e.project_id = #{projectId}
AND s.scene_id = #{sceneId}
AND s.status = #{status}
ORDER BY e.sort_order ASC, sc.sort_order ASC, s.sort_order ASC
